def _rel(path: str | Path) -> Path:
    return ROOT / Path(path)

def _backup(path: Path) -> str | None:
    if not path.exists(): return None
    BACKUP_ROOT.mkdir(parents=True, exist_ok=True)
    safe = "__".join(path.relative_to(ROOT).parts) + f".before_{PATCH_ID}"
    target = BACKUP_ROOT / safe
    target.parent.mkdir(parents=True, exist_ok=True)
    if not target.exists(): shutil.copy2(path, target)
    return str(target)

def _read(path: Path) -> str:
    return path.read_text(encoding="utf-8") if path.exists() else ""

def _write(path: str | Path, content: str) -> dict[str, Any]:
    p=_rel(path); existed=p.exists(); backup=_backup(p); p.parent.mkdir(parents=True, exist_ok=True); old=_read(p); mutated=old!=content
    if mutated: p.write_text(content, encoding="utf-8", newline="\n")
    return {"path": str(Path(path)), "existed_before": existed, "backup_path": backup, "mutated": mutated}

def _append_or_replace(path: str | Path, block: str, marker: str) -> dict[str, Any]:
    p=_rel(path); existed=p.exists(); backup=_backup(p); p.parent.mkdir(parents=True, exist_ok=True); old=_read(p); start=f"# >>> {marker}"; end=f"# <<< {marker}"; payload=f"\n{start}\n{block.rstrip()}\n{end}\n"
    if start in old and end in old:
        before, rest = old.split(start, 1); _, after = rest.split(end, 1); new = before.rstrip() + payload + after.lstrip("\n")
    else:
        new = old.rstrip() + payload
    mutated = old != new
    if mutated: p.write_text(new, encoding="utf-8", newline="\n")
    return {"path": str(Path(path)), "existed_before": existed, "backup_path": backup, "mutated": mutated}

