    compile_targets=["src/tradebot/api.py", "src/tradebot/config_safety.py", "src/tradebot/ui/dashboard.py", "src/tradebot/engine.py", "tools/check_4B436662F_H5_api_config_engine_rehydration_stop_cleanup_hotfix.py", "tools/run_4B436662F_H5_api_config_engine_rehydration_stop_cleanup_hotfix.py", "tests/test_full_repo_regression_stabilization_4B436662F_H5.py"]
